#include <stdio.h>
#include <stdlib.h>
#include <string.h>

typedef long long ll;

/* Fenwick tree for long long values */
struct Fenwick {
    int n;
    ll *bit;
    void init(int n_) {
        n = n_;
        bit = (ll*)calloc(n+2, sizeof(ll));
    }
    void add(int idx, ll val) {
        for (int i = idx; i <= n; i += i & -i) bit[i] += val;
    }
    ll sum(int idx) {
        ll res = 0;
        for (int i = idx; i > 0; i -= i & -i) res += bit[i];
        return res;
    }
};

struct Op {
    char type; // 'P', 'M', 'B'
    int a, b;  // parameters as described in analysis
};

int main() {
    int T;
    if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int n, m;
        scanf("%d %d", &n, &m);
        struct Op *ops = (struct Op*)malloc(m * sizeof(struct Op));
        int maxSystems = 0;
        int *curL = (int*)calloc(m+2, sizeof(int)); // enough for all possible systems
        int *curR = (int*)calloc(m+2, sizeof(int));
        int *tempL = (int*)calloc(m+2, sizeof(int)); // temporary for simulation while reading
        int *tempR = (int*)calloc(m+2, sizeof(int));
        int sysCnt = 0;
        // collect coordinates for compression
        int coordCap = 3*m + 5;
        ll *coords = (ll*)malloc(coordCap * sizeof(ll));
        int coordSize = 0;
        for (int i = 0; i < m; ++i) {
            char buf[2];
            scanf(" %1s", buf);
            ops[i].type = buf[0];
            if (ops[i].type == 'P') {
                int u, v;
                scanf("%d %d", &u, &v);
                ops[i].a = u; ops[i].b = v;
                ++sysCnt;
                tempL[sysCnt] = u;
                tempR[sysCnt] = v;
                // add coordinates u and v+1
                coords[coordSize++] = u;
                coords[coordSize++] = (ll)v + 1;
            } else if (ops[i].type == 'M') {
                int id, d;
                scanf("%d %d", &id, &d);
                ops[i].a = id; ops[i].b = d;
                int oldL = tempL[id];
                int oldR = tempR[id];
                int newL = oldL + d;
                int newR = oldR + d;
                tempL[id] = newL;
                tempR[id] = newR;
                // coordinates for new interval
                coords[coordSize++] = newL;
                coords[coordSize++] = (ll)newR + 1;
            } else if (ops[i].type == 'B') {
                int x; scanf("%d", &x);
                ops[i].a = x; ops[i].b = 0;
                coords[coordSize++] = x;
            }
        }
        // also need coordinates for right+1 of intervals that will be removed later (already added when they were created)
        // sort and deduplicate coordinates
        qsort(coords, coordSize, sizeof(ll), (int(*)(const void*,const void*))strcmp);
        // custom comparator for qsort of ll
        // Since we cannot pass strcmp for ll, implement a simple lambda via function pointer is not allowed in C89.
        // We'll write a separate comparator.
        // Re‑sort with proper comparator.
        int cmp_ll(const void *a, const void *b) {
            ll va = *(const ll*)a;
            ll vb = *(const ll*)b;
            return (va > vb) - (va < vb);
        }
        qsort(coords, coordSize, sizeof(ll), cmp_ll);
        int uniq = 0;
        for (int i = 0; i < coordSize; ++i) {
            if (i == 0 || coords[i] != coords[i-1]) {
                coords[uniq++] = coords[i];
            }
        }
        // mapping function: binary search
        int getIdx(ll x) {
            int l = 0, r = uniq-1;
            while (l <= r) {
                int mid = (l+r)/2;
                if (coords[mid] == x) return mid+1; // Fenwick is 1‑based
                else if (coords[mid] < x) l = mid+1;
                else r = mid-1;
            }
            return -1; // should never happen
        }
        struct Fenwick ft;
        ft.init(uniq+2);
        // reset current intervals for real processing
        memset(curL, 0, (m+2)*sizeof(int));
        memset(curR, 0, (m+2)*sizeof(int));
        sysCnt = 0;
        for (int i = 0; i < m; ++i) {
            if (ops[i].type == 'P') {
                int u = ops[i].a;
                int v = ops[i].b;
                ++sysCnt;
                curL[sysCnt] = u;
                curR[sysCnt] = v;
                ft.add(getIdx(u), 1);
                ft.add(getIdx((ll)v+1), -1);
            } else if (ops[i].type == 'M') {
                int id = ops[i].a;
                int d = ops[i].b;
                int oldL = curL[id];
                int oldR = curR[id];
                // remove old interval
                ft.add(getIdx(oldL), -1);
                ft.add(getIdx((ll)oldR+1), 1);
                int newL = oldL + d;
                int newR = oldR + d;
                curL[id] = newL;
                curR[id] = newR;
                // add new interval
                ft.add(getIdx(newL), 1);
                ft.add(getIdx((ll)newR+1), -1);
            } else { // 'B'
                int x = ops[i].a;
                ll ans = ft.sum(getIdx(x));
                printf("%lld\n", ans);
            }
        }
        free(ops);
        free(curL);
        free(curR);
        free(tempL);
        free(tempR);
        free(coords);
    }
    return 0;
}
